const raw  = $input.item.json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
return [{ json: { _ticker_context: true, ticker: (body.ticker || '').toString().toUpperCase().trim() } }];

const all    = $input.all().map(i => i.json);
const ctx    = all.find(r => r._ticker_context);
const ticker = ctx ? ctx.ticker : '';
if (!ticker) return [{ json: { found: false, reason: 'No ticker provided' } }];

const sheetRows  = all.filter(r => !r._ticker_context && r.Timestamp);
const tickerRows = sheetRows.filter(r => (r.Ticker||'').toUpperCase() === ticker);

if (!tickerRows.length) {
  return [{ json: { found: false, ticker,
    reason: 'Ticker not yet in live pipeline scan — using Grok-3 analysis' } }];
}

tickerRows.sort((a,b) => new Date(b.Timestamp||0) - new Date(a.Timestamp||0));
const latest = tickerRows[0];
const ageH   = (Date.now() - new Date(latest.Timestamp||0).getTime()) / 3600000;

let reasons = [];
try {
  const r = latest.Reasons||'';
  reasons = r.startsWith('[') ? JSON.parse(r) : r.split('|').map(s=>s.trim()).filter(Boolean);
} catch(_) {}
if (!reasons.length) reasons = ['Signal generated by AgilityServ Quantum Pipeline'];

return [{ json: {
  found:true, stale: ageH>24, ticker: latest.Ticker||ticker,
  signal: latest.Signal||'STAND ASIDE',
  confidence: Number(latest.Confidence)||0, price: Number(latest.Price)||0,
  regime: latest.Regime||'', rsi: Number(latest.RSI)||null,
  vcVerdict: latest.VC_Verdict||'',
  entry: Number(latest.Entry)||null, stop: Number(latest.Stop)||null,
  target1: Number(latest.Target1)||null, target2: Number(latest.Target2)||null,
  timeframe: latest.TimeFrame||'intraday', reasons,
  signalAge: `${ageH.toFixed(1)}h ago`, timestamp: latest.Timestamp,
  pipelineVersion: latest.Pipeline_Version||'v5.16',
  source: 'AgilityServ Quantum Pipeline'
}}];
